  onOpenChange: (open: boolean) => void
  shouldFilter?: boolean
  children: React.ReactNode
}) {
  const contentRef = React.useRef<HTMLDivElement>(null)

  // Escape to close
  React.useEffect(() => {
    if (!open) return
    function handleKeyDown(e: KeyboardEvent) {
